async (page) => {
  const clickAndWait = async (cx, cy, ms = 3000) => {
    await page.evaluate(({x, y}) => {
      document.getElementById('cursor').dispatchEvent(new MouseEvent('click', {
        clientX: x, clientY: y, bubbles: true, ctrlKey: false
      }));
    }, {x: cx, y: cy});
    await page.waitForTimeout(ms);
    return await page.evaluate(() => {
      const s = window.__latestGameState;
      return {x: s.player_position.x, y: s.player_position.y, hp: s.player_stats.hp};
    });
  };

  // Path: (192,155) → (193,149) → (194,143) → (199,141) → (200,135) ...
  // Each step, recalculate canvas coords from new player position
  // Step 1: go to (193, 149) - from (192, 155), first waypoint
  // CX=648, CY=384, TILE_PX=48

  // Waypoint (193, 149): Δx=1E, Δy=-6N → cx=648+48=696, cy=384-288=96
  let pos = await clickAndWait(696, 96);
  console.log('After step 1:', JSON.stringify(pos));

  if (pos.y > 150) {
    // Didn't reach - try a canvas click directly on walkable tile
    pos = await clickAndWait(696, 150); // Less aggressive
  }

  return JSON.stringify(pos);
}

async (page) => {
  await page.evaluate(() => window.game.player.go(216, 115));
  await page.waitForTimeout(8000);

  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {x: s.player_position.x, y: s.player_position.y, hp: s.player_stats.hp};
  });

  // Talk to Forester if adjacent
  if (Math.abs(pos.x - 216) + Math.abs(pos.y - 114) <= 2) {
    const talkResult = await page.evaluate(() => JSON.stringify(window.__interactNPC('Forester')));
    await page.waitForTimeout(1500);
    const state = await page.evaluate(() => {
      const s = window.__latestGameState;
      return {dialogue: s.ui_state.npc_dialogue, questPanel: s.ui_state.quest_panel_visible};
    });
    return JSON.stringify({pos, talkResult: JSON.parse(talkResult), state});
  }

  return JSON.stringify({pos, note: 'not adjacent yet'});
}

async (page) => {
  // Set Chop style (7 = Accuracy + Defense) to build Accuracy toward 15 for Coder's Glitch quest
  await page.evaluate(() => window.game.player.setAttackStyle(7));
  await page.waitForTimeout(500);

  // Navigate past Guard at (231, 145) into desert zone
  await page.evaluate(() => window.game.player.go(240, 145));
  await page.waitForTimeout(10000);

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const map = window.__latestAsciiMap;
    return {
      pos: s.player_position,
      hp: s.player_stats.hp,
      maxhp: s.player_stats.max_hp,
      nearbyMobs: map ? map.legendText.split('\n').filter(l => l.includes('[') && (l.includes('(HP:') || l.includes('Scor') || l.includes('Gob'))).slice(0, 5) : []
    };
  });
  return JSON.stringify(state);
}

async (page) => {
  // Check current state after warp, and verify attack style
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    const style = window.game?.player?.attackStyle;
    return {
      pos: s.player_position,
      hp: s.player_stats.hp,
      maxhp: s.player_stats.max_hp,
      level: s.player_stats.level,
      skills: s.skills,
      attackStyle: style,
      isDead: s.ui_state.is_dead,
      respawn: s.ui_state.respawn_button_visible
    };
  });
  return JSON.stringify(state, null, 2);
}

