async (page) => {
  // Kill nearby mobs first to clear aggro, then navigate to desert
  // Attack the Rat (E1) and Batterfly (E6) to clear the area
  let r = await page.evaluate(() => JSON.stringify(window.__attackMob('Rat')));
  await page.waitForTimeout(4000);
  r = await page.evaluate(() => JSON.stringify(window.__attackMob('Batterfly')));
  await page.waitForTimeout(6000);

  // Now navigate to desert zone
  await page.evaluate(() => window.game.player.go(260, 140));
  await page.waitForTimeout(10000);

  const pos = await page.evaluate(() => {
    const s = window.__latestGameState;
    return {x: s.player_position.x, y: s.player_position.y, hp: s.player_stats.hp};
  });

  if (pos.x < 230) {
    // Still not in desert, try again
    await page.evaluate(() => window.game.player.go(260, 140));
    await page.waitForTimeout(10000);
  }

  const finalPos = await page.evaluate(() => {
    const s = window.__latestGameState;
    const map = window.__latestAsciiMap;
    return {pos: s.player_position, hp: s.player_stats.hp, 
            mobs: map ? map.legendText.split('\n').filter(l => l.includes('HP:')).slice(0,5).join(' | ') : ''};
  });
  return JSON.stringify(finalPos);
}
